const data = $input.first().json;
const list = data.list || [];
const date = data.date || '';
const dashUrl = data.dashboard_url || '';

if (list.length === 0) {
  return [{ json: { message: `📋 ${date}\n本日の後確対象者はいません✅`, skip: true } }];
}

// 色別にグループ化
const white  = list.filter(c => c.fp_color_status === 'white');
const yellow = list.filter(c => c.fp_color_status === 'yellow');
const red    = list.filter(c => c.fp_color_status === 'red');
const green  = list.filter(c => c.fp_color_status === 'green');

const formatCustomer = (c) => {
  const name = (c.fp_last_name + c.fp_first_name) || `${c.hitomono_id}（名前未照合）`;
  return `  • ${c.hitomono_id} ${name}様`;
};

let lines = [`📋 本日の後確リスト（${list.length}件）\n${date}\n`];

if (white.length > 0) {
  lines.push(`⬜ マッチング待ち（${white.length}件）\n→ LINEで名前照合して後追い`);
  lines.push(...white.map(formatCustomer));
  lines.push('');
}
if (yellow.length > 0) {
  lines.push(`🟡 マッチング完了（${yellow.length}件）\n→ 面談日程を確認`);
  lines.push(...yellow.map(formatCustomer));
  lines.push('');
}
if (red.length > 0) {
  lines.push(`🔴 面談意思なし（${red.length}件）\n→ 対応確認が必要`);
  lines.push(...red.map(formatCustomer));
  lines.push('');
}
if (green.length > 0) {
  lines.push(`🟢 意思確認が不安（${green.length}件）\n→ 丁寧なフォロー`);
  lines.push(...green.map(formatCustomer));
  lines.push('');
}

lines.push(`▼ 電話後はこちらで結果入力\n${dashUrl}`);

const message = lines.join('\n');
return [{ json: { message, list, skip: false } }];
